import{_ as t,o as a,c as r,ae as l}from"./chunks/framework.B1ddJaIi.js";const m=JSON.parse('{"title":"linux系统命令","description":"","frontmatter":{},"headers":[],"relativePath":"program/cpp/linuxCommand.md","filePath":"program/cpp/linuxCommand.md","lastUpdated":1666363606000}'),n={name:"program/cpp/linuxCommand.md"};function i(c,e,o,s,d,p){return a(),r("div",null,[...e[0]||(e[0]=[l('<h1 id="linux系统命令" tabindex="-1">linux系统命令 <a class="header-anchor" href="#linux系统命令" aria-label="Permalink to &quot;linux系统命令&quot;">​</a></h1><h2 id="yum" tabindex="-1">yum <a class="header-anchor" href="#yum" aria-label="Permalink to &quot;yum&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">语法</th><th style="text-align:center;">作用</th></tr></thead><tbody><tr><td style="text-align:center;">yum list installed</td><td style="text-align:center;">显式已经安装的包</td></tr><tr><td style="text-align:center;">yum list xxx</td><td style="text-align:center;">查找可安装xx的包</td></tr><tr><td style="text-align:center;">yum install xxx</td><td style="text-align:center;">安装xxx的包</td></tr><tr><td style="text-align:center;">yum remove xxx</td><td style="text-align:center;">卸载xxx的包</td></tr><tr><td style="text-align:center;">yum deplist xxx</td><td style="text-align:center;">列出xxx的包依赖</td></tr><tr><td style="text-align:center;">yum -y</td><td style="text-align:center;">自动选择是</td></tr><tr><td style="text-align:center;">yum info</td><td style="text-align:center;">显式软件包的信息</td></tr><tr><td style="text-align:center;">yum update</td><td style="text-align:center;">升级所有的包</td></tr><tr><td style="text-align:center;">yum check-update</td><td style="text-align:center;">检查可更新的程序</td></tr></tbody></table><h2 id="更换centos镜像" tabindex="-1">更换centos镜像 <a class="header-anchor" href="#更换centos镜像" aria-label="Permalink to &quot;更换centos镜像&quot;">​</a></h2><p>wget -O /etc/yum.repos.d/CentOS-Base.repo <a href="http://mirrors.aliyun.com/repo/Centos-7.repo" target="_blank" rel="noreferrer">http://mirrors.aliyun.com/repo/Centos-7.repo</a></p><p>grep -rl &#39;cloud.aliyuncs&#39; ./ | xargs sed -i &#39;s/cloud.aliyuncs/aliyun/g&#39;</p><p>yum clean all</p><p>yum makecache</p><h2 id="更换epel源" tabindex="-1">更换epel源 <a class="header-anchor" href="#更换epel源" aria-label="Permalink to &quot;更换epel源&quot;">​</a></h2><p>wget -O /etc/yum.repos.d/epel.repo <a href="http://mirrors.aliyun.com/repo/epel-7.repo" target="_blank" rel="noreferrer">http://mirrors.aliyun.com/repo/epel-7.repo</a></p><p>yum clean all</p><p>yum makecache</p><h2 id="gcc编译" tabindex="-1">gcc编译 <a class="header-anchor" href="#gcc编译" aria-label="Permalink to &quot;gcc编译&quot;">​</a></h2><p>yum -y install gmp-devel yum -y install mpfr-devel yum -y install libmpc-devel yum -y install bzip2 wget <a href="https://mirrors.ustc.edu.cn/gnu/gcc/gcc-7.3.0/gcc-7.3.0.tar.gz" target="_blank" rel="noreferrer">https://mirrors.ustc.edu.cn/gnu/gcc/gcc-7.3.0/gcc-7.3.0.tar.gz</a> ./contrib/download_prerequisites mkdir gcc-build-7.3.0 cd gcc-build-7.3.0 ../configure --enable-languages=c,c++ --disable-multilib --with-system-zlib --prefix=/usr/local/gcc7.3.0 make -j export LD_LIBRARY_PATH=/usr/local/gcc7.3.0/lib64:$LD_LIBRARY_PATH</p><h2 id="创建交换分区" tabindex="-1">创建交换分区 <a class="header-anchor" href="#创建交换分区" aria-label="Permalink to &quot;创建交换分区&quot;">​</a></h2><p>sudo dd if=/dev/zero of=/swapfile bs=1M count=4096 # 1 * 2048 = 2048 创建 1 g 的内存分区 sudo mkswap /swapfile sudo swapon /swapfile sudo swapoff /swapfile sudo rm /swapfile</p><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><p>CentOS 初体验三： Yum 安装、卸载软件 <a href="https://blog.csdn.net/zhaoyanjun6/article/details/78894974" target="_blank" rel="noreferrer">https://blog.csdn.net/zhaoyanjun6/article/details/78894974</a></p><p>Redhat 或者centos 更换第三方epel源 <a href="https://developer.aliyun.com/article/516685" target="_blank" rel="noreferrer">https://developer.aliyun.com/article/516685</a></p>',19)])])}const x=t(n,[["render",i]]);export{m as __pageData,x as default};
